async (params, browser) => {
  // Search Walmart
  await browser.open(`https://www.walmart.com/search?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[data-testid=\'list-view\'] [data-item-id], [class*=\'search-result\'], [class*=\'product-card\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract product results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[data-item-id], [class*="product-card"], [class*="search-result-gridview-item"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('[data-automation-id="product-title"], [class*="product-title"] a, a[class*="product"] span, [class*="title"] a'); const priceEl = el.querySelector('[data-automation-id="product-price"], [class*="price"] [class*="current"], [class*="price-main"]'); const ratingEl = el.querySelector('[class*="rating"] [class*="stars"], [data-testid="product-ratings"], [class*="stars-container"]'); const reviewCountEl = el.querySelector('[class*="rating"] [class*="count"], [class*="review-count"]'); const linkEl = el.querySelector('a[href*="/ip/"]'); const imgEl = el.querySelector('img[src*="walmart"], img[data-testid], img'); const sellerEl = el.querySelector('[class*="seller"], [class*="fulfilled"]'); const shippingEl = el.querySelector('[class*="shipping"], [class*="delivery"], [class*="fulfillment"]'); results.push({ title: titleEl ? titleEl.textContent.trim().substring(0, 200) : '', price: priceEl ? priceEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', seller: sellerEl ? sellerEl.textContent.trim() : '', shipping: shippingEl ? shippingEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
